# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
from sklearn.model_selection import train_test_split
from sklearn.svm import SVC

app = Flask(__name__)

# In-memory storage for labels
labels_storage = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    
    labels_storage[image_id].append(label)
    return jsonify({"status": "success"})

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in labels_storage.items():
        most_common_label = max(set(labels), key=labels.count)
        aggregated_labels[image_id] = most_common_label
    
    return jsonify(aggregated_labels)

@app.route('/train_model', methods=['POST'])
def train_model():
    all_images = request.get_json()
    
    X = []
    y = []
    for image_data in all_images:
        image_id = image_data['image_id']
        label = labels_storage[image_id][0]  # Assuming majority voting has already been done
        feature_vector = image_data['features']  # Replace with actual feature extraction logic
        X.append(feature_vector)
        y.append(label)
    
    model = SVC()
    model.fit(X, y)
    return jsonify({"status": "model trained"})

if __name__ == '__main__':
    app.run(debug=True)